const WARNING_TYPE = 'VALIDATION_DRIFT_SHEETS_PG';
const now = new Date();
const runDate = now.toISOString().slice(0, 10);

function all(name) {
  try { return $(name).all().map(item => item.json); } catch (_) { return []; }
}
function first(name) {
  const rows = all(name);
  return rows[0] || {};
}
function clean(value) { return String(value ?? '').trim(); }
function num(value) { const n = Number(clean(value).replace(',', '.')); return Number.isFinite(n) ? n : 0; }
function cents(value) { return Math.round(num(value) * 100) / 100; }
function warning(subject, message, details = {}) {
  return {
    event_type: 'warning',
    batch_run_id: `wf-val_${runDate}`,
    data: {
      warning_key: `${WARNING_TYPE}|${subject}|${runDate}`,
      warning_type: WARNING_TYPE,
      severity: subject === 'BACKUP_OK' ? 'critical' : 'warning',
      subject_key: subject,
      source_workflow: 'wf-val',
      message,
      details,
    },
  };
}

const txRows = all('Google Sheets - Verarbeitete_Transaktionen');
const guvRows = all('Google Sheets - GuV_Tagesposten');
const productRows = all('Google Sheets - Produkte');
const batchRows = all('Google Sheets - Lagerchargen');
const pg = first('Postgres - Validation Snapshot').postgres_snapshot || first('Postgres - Validation Snapshot') || {};
const events = [];

const sheetTxRevenue = cents(txRows.reduce((sum, row) => sum + num(row.gross_amount ?? row.Brutto ?? row.Umsatz ?? row.amount), 0));
const pgTxRevenue = cents(pg.transactions?.grossRevenue);
if (txRows.length !== num(pg.transactions?.count) || Math.abs(sheetTxRevenue - pgTxRevenue) > 0.01) {
  events.push(warning('TRANSACTIONS', `Transactions drift: Sheets ${txRows.length}/${sheetTxRevenue.toFixed(2)} vs PG ${num(pg.transactions?.count)}/${pgTxRevenue.toFixed(2)}`));
}

const sheetGuvKeys = new Set(guvRows.map(row => [row.posting_date ?? row.Datum ?? row.date, row.machine_id ?? row.MachineID ?? '457107528', row.mdb_code ?? row.MDB, row.product_key ?? row.SKU].map(clean).join('|')));
const pgGuvKeys = new Set((pg.guvDaily || []).map(row => clean(row.key)));
const guvDiff = [...sheetGuvKeys].filter(key => key && !pgGuvKeys.has(key));
if (guvDiff.length) events.push(warning('GUV_DAILY', `GuV daily drift in ${guvDiff.length} key(s)`, { keys: guvDiff.slice(0, 20) }));

const sheetSlots = new Set(productRows.filter(row => ['true', 'ja', 'yes', '1', 'active'].includes(clean(row.active ?? row.aktiv).toLowerCase())).map(row => [row.machine_id ?? '457107528', row.mdb_code ?? row.MDB, row.product_key ?? row.SKU].map(clean).join('|')));
const pgSlots = new Set(pg.activeSlots || []);
const slotDiff = [...sheetSlots].filter(key => key && !pgSlots.has(key));
if (slotDiff.length) events.push(warning('SLOT_ACTIVE', `Active slot drift in ${slotDiff.length} slot(s)`, { keys: slotDiff.slice(0, 20) }));

const aliases = new Set((pg.productAliases || []).map(row => clean(row.alias)));
const mappedUnmatched = (pg.unmappedSales || []).filter(row => aliases.has(clean(row.productNameRaw)));
if (mappedUnmatched.length) events.push(warning('PRODUCT_MAPPING', `Product mapping drift for ${mappedUnmatched.length} PG sale(s)`, { sales: mappedUnmatched.slice(0, 20) }));

const pgPrices = new Map((pg.prices || []).map(row => [clean(row.productKey), cents(row.priceGross)]));
const priceDiff = productRows.filter(row => pgPrices.has(clean(row.product_key ?? row.SKU)) && Math.abs(cents(row.price_gross ?? row.Preis ?? row.price) - pgPrices.get(clean(row.product_key ?? row.SKU))) > 0.01);
if (priceDiff.length) events.push(warning('PRICE_SAMPLE', `Price sample drift for ${priceDiff.length} product(s)`, { products: priceDiff.slice(0, 20).map(row => clean(row.product_key ?? row.SKU)) }));

const batchQtyByKey = new Map(batchRows.map(row => [clean(row.batch_key ?? row.batch_id ?? row.Charge), num(row.initial_qty ?? row.Anfangsbestand) - num(row.remaining_qty ?? row.Restbestand)]));
const stockDiff = (pg.stockMovements || []).filter(row => batchQtyByKey.has(clean(row.batchKey)) && num(row.movementTotal) !== batchQtyByKey.get(clean(row.batchKey)));
if (stockDiff.length) events.push(warning('STOCK_MOVEMENT_BALANCE', `Stock movement balance drift for ${stockDiff.length} batch(es)`, { batches: stockDiff.slice(0, 20).map(row => row.batchKey) }));

const backupAt = pg.lastBackupOkAt ? new Date(pg.lastBackupOkAt).getTime() : 0;
if (!backupAt || (Date.now() - backupAt) / 36e5 > 26) {
  events.push(warning('BACKUP_OK', 'BACKUP_OK missing for more than 26 hours', { lastBackupOkAt: pg.lastBackupOkAt || null }));
}

const text = [`WF-Val Validation Report ${runDate}`, '', `${events.length} Drift-Warnungen`, '', ...events.map(event => `${event.data.subject_key}: ${event.data.message}`)].join('\n');
const mail = { sendTo: 'PatrickZinke@gmx.net', subject: events.length ? `WF-Val ${runDate}: ${events.length} Drift-Warnungen` : `WF-Val ${runDate}: keine Drift`, text, html: `<pre>${text}</pre>` };
return [{ json: { warningEvents: events, mail, status: events.length ? 'drift' : 'ok' } }];
